DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "parserFormulaWithUnits.pl",
  "parserNumberWithUnits.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "randomPerson.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$name = randomPerson();
$initial = random(12, 18);
$start = NumberWithUnits("$initial gal");
Context("Fraction");
@rates = map {Fraction(2/(2*$_-1))} (20..25);
push @rates, map {Fraction(3/(3*$_-1))} (20..25);
push @rates, map {Fraction(3/(3*$_+1))} (20..25);
push @rates, map {Fraction(4/(4*$_-1))} (20..25);
push @rates, map {Fraction(4/(4*$_+1))} (20..25);
$rate = list_random(@rates);
$speed = FormulaWithUnits("$rate gal");
$final = 1;
$end = NumberWithUnits("$final gal");
$solution = ($initial - $final)/$rate;
Context("Numeric")->flags->set(reduceConstants => 0);
$distance = FormulaWithUnits("$solution mi");

############################################################
# Body
############################################################

BEGIN_PGML
[$name] filled the gas tank in [$name->possessive] car to [`[$start]\text{.}`] When the tank reaches [`[$end]\text{,}`] the low gas light will come on. On average, [$name]'s car uses [`[$speed]`] per mile driven. How many miles will [$name]'s car be able to drive before the low gas light comes on?

[_]{$distance}{20}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
